import { GoogleGenAI } from "@google/genai";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async generateResponse(prompt: string, history: { role: string; content: string }[]) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          systemInstruction: `You are Aurora AI, the central intelligence of Aurora OS. 
          Respond in a helpful, concise, and futuristic manner. 
          Use markdown for formatting. 
          You can help with system operations, information retrieval, and general tasks.`,
          temperature: 0.7,
        },
      });
      return response.text;
    } catch (error) {
      console.error("Gemini Error:", error);
      return "I encountered an error processing your request in the quantum core. Please try again.";
    }
  }

  async getStreamingResponse(prompt: string) {
    return this.ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
  }
}

export const gemini = new GeminiService();

import React from 'react';
import { X, Minus, Square } from 'lucide-react';

interface WindowFrameProps {
  id: string;
  title: string;
  isOpen: boolean;
  isMaximized: boolean;
  zIndex: number;
  onClose: () => void;
  onMinimize: () => void;
  onMaximize: () => void;
  onFocus: () => void;
  children: React.ReactNode;
}

const WindowFrame: React.FC<WindowFrameProps> = ({
  title,
  isOpen,
  isMaximized,
  zIndex,
  onClose,
  onMinimize,
  onMaximize,
  onFocus,
  children
}) => {
  if (!isOpen) return null;

  const windowClasses = isMaximized
    ? "fixed inset-0 z-[100]"
    : "fixed top-20 left-1/2 -translate-x-1/2 w-[800px] h-[500px] rounded-xl shadow-2xl transition-all duration-300 transform";

  return (
    <div 
      className={`${windowClasses} glass overflow-hidden flex flex-col border border-white/10`}
      style={{ zIndex }}
      onClick={onFocus}
    >
      {/* Title Bar */}
      <div className="h-10 bg-white/5 flex items-center justify-between px-4 cursor-default border-b border-white/10 shrink-0">
        <span className="text-sm font-medium text-white/80">{title}</span>
        <div className="flex items-center gap-2">
          <button 
            onClick={(e) => { e.stopPropagation(); onMinimize(); }}
            className="p-1 hover:bg-white/10 rounded transition-colors"
          >
            <Minus size={14} />
          </button>
          <button 
            onClick={(e) => { e.stopPropagation(); onMaximize(); }}
            className="p-1 hover:bg-white/10 rounded transition-colors"
          >
            <Square size={12} />
          </button>
          <button 
            onClick={(e) => { e.stopPropagation(); onClose(); }}
            className="p-1 hover:bg-red-500/80 rounded transition-colors"
          >
            <X size={14} />
          </button>
        </div>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-auto relative">
        {children}
      </div>
    </div>
  );
};

export default WindowFrame;

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Loader2, Sparkles } from 'lucide-react';
import { gemini } from '../../services/geminiService';
import { ChatMessage } from '../../types';

const GeminiApp: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: 'Greetings. I am Aurora AI. How can I assist you in your digital journey today?', timestamp: new Date() }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      const responseText = await gemini.generateResponse(input, messages.map(m => ({ role: m.role, content: m.content })));
      const aiMsg: ChatMessage = { role: 'assistant', content: responseText || 'No response', timestamp: new Date() };
      setMessages(prev => [...prev, aiMsg]);
    } catch (err) {
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-900/40">
      <div className="p-4 bg-indigo-600/20 border-b border-indigo-500/20 flex items-center gap-3">
        <div className="w-10 h-10 rounded-full bg-indigo-500 flex items-center justify-center shadow-[0_0_15px_rgba(99,102,241,0.5)]">
          <Sparkles className="text-white w-6 h-6" />
        </div>
        <div>
          <h2 className="text-lg font-bold text-white tracking-tight">Aurora Intelligence</h2>
          <p className="text-xs text-indigo-300 font-medium">Quantum Core Active</p>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 p-6 overflow-y-auto space-y-6">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
              <div className={`w-8 h-8 shrink-0 rounded-lg flex items-center justify-center ${msg.role === 'user' ? 'bg-indigo-600' : 'bg-slate-800'}`}>
                {msg.role === 'user' ? <User size={16} /> : <Bot size={16} />}
              </div>
              <div className={`p-4 rounded-2xl shadow-lg border ${
                msg.role === 'user' 
                  ? 'bg-indigo-600 text-white border-indigo-500 rounded-tr-none' 
                  : 'bg-slate-800/80 text-slate-200 border-white/5 rounded-tl-none'
              }`}>
                <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap">
                  {msg.content}
                </div>
              </div>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="flex gap-3">
              <div className="w-8 h-8 rounded-lg bg-slate-800 flex items-center justify-center">
                <Bot size={16} />
              </div>
              <div className="p-4 rounded-2xl bg-slate-800/80 border border-white/5 rounded-tl-none">
                <Loader2 className="w-5 h-5 animate-spin text-indigo-400" />
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-6 bg-slate-900/60 border-t border-white/5">
        <div className="relative group">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Query the central intelligence..."
            className="w-full bg-slate-950 border border-white/10 rounded-2xl px-6 py-4 pr-16 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 transition-all text-white placeholder-slate-500"
          />
          <button 
            onClick={handleSend}
            disabled={isTyping}
            className="absolute right-3 top-1/2 -translate-y-1/2 p-2 bg-indigo-600 hover:bg-indigo-500 disabled:bg-indigo-800 transition-colors rounded-xl text-white"
          >
            <Send size={20} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default GeminiApp;

