import React, { useEffect, useState } from 'react';
import { LineChart, Line, AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { Activity, Cpu, Database, Zap } from 'lucide-react';

const SystemMonitor: React.FC = () => {
  const [metrics, setMetrics] = useState<any[]>([]);

  useEffect(() => {
    const interval = setInterval(() => {
      setMetrics(prev => {
        const newVal = {
          time: new Date().toLocaleTimeString(),
          cpu: 20 + Math.random() * 40,
          ram: 45 + Math.random() * 10,
          energy: 70 + Math.random() * 30
        };
        const updated = [...prev, newVal];
        return updated.length > 20 ? updated.slice(1) : updated;
      });
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  const Card = ({ title, icon, value, color, unit }: any) => (
    <div className="glass p-4 rounded-xl flex flex-col justify-between border-white/5">
      <div className="flex items-center justify-between mb-2">
        <span className="text-xs font-bold text-white/40 uppercase tracking-widest">{title}</span>
        <div className={`${color} text-white p-1.5 rounded-lg shadow-lg`}>
          {icon}
        </div>
      </div>
      <div className="flex items-baseline gap-1">
        <span className="text-2xl font-bold text-white">{value.toFixed(1)}</span>
        <span className="text-xs text-white/40">{unit}</span>
      </div>
    </div>
  );

  return (
    <div className="flex flex-col h-full bg-slate-950 p-6 gap-6">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <Card title="CPU Usage" icon={<Cpu size={18} />} value={metrics[metrics.length-1]?.cpu || 0} color="bg-emerald-500" unit="%" />
        <Card title="Memory Pool" icon={<Database size={18} />} value={metrics[metrics.length-1]?.ram || 0} color="bg-blue-500" unit="GB" />
        <Card title="Aurora Flow" icon={<Zap size={18} />} value={metrics[metrics.length-1]?.energy || 0} color="bg-amber-500" unit="W" />
      </div>

      <div className="flex-1 glass p-6 rounded-2xl border-white/5 flex flex-col">
        <div className="flex items-center gap-2 mb-6">
          <Activity size={20} className="text-emerald-400" />
          <h3 className="font-bold text-lg">Live Core Flux</h3>
        </div>
        <div className="flex-1 w-full min-h-[200px]">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={metrics}>
              <defs>
                <linearGradient id="colorCpu" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#10b981" stopOpacity={0.3}/>
                  <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.05)" vertical={false} />
              <XAxis dataKey="time" hide />
              <YAxis domain={[0, 100]} stroke="rgba(255,255,255,0.2)" fontSize={10} />
              <Tooltip 
                contentStyle={{ backgroundColor: '#0f172a', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '8px' }}
                itemStyle={{ fontSize: '12px' }}
              />
              <Area type="monotone" dataKey="cpu" stroke="#10b981" fillOpacity={1} fill="url(#colorCpu)" strokeWidth={2} />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

export default SystemMonitor;

import React, { useState, useEffect } from 'react';
import { APPS_CONFIG } from './constants';
import { AppId, AppWindow } from './types';
import WindowFrame from './components/WindowFrame';
import GeminiApp from './components/apps/GeminiApp';
import FileExplorer from './components/apps/FileExplorer';
import SystemMonitor from './components/apps/SystemMonitor';
import { Monitor, Battery, Wifi, Volume2, Search, Power } from 'lucide-react';

const App: React.FC = () => {
  const [windows, setWindows] = useState<AppWindow[]>([
    { id: 'gemini', title: APPS_CONFIG.gemini.name, isOpen: false, isMaximized: false, zIndex: 10 },
    { id: 'files', title: APPS_CONFIG.files.name, isOpen: false, isMaximized: false, zIndex: 10 },
    { id: 'monitor', title: APPS_CONFIG.monitor.name, isOpen: false, isMaximized: false, zIndex: 10 },
    { id: 'settings', title: APPS_CONFIG.settings.name, isOpen: false, isMaximized: false, zIndex: 10 },
    { id: 'browser', title: APPS_CONFIG.browser.name, isOpen: false, isMaximized: false, zIndex: 10 },
  ]);

  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const toggleWindow = (id: AppId) => {
    setWindows(prev => prev.map(win => {
      if (win.id === id) {
        const nextState = !win.isOpen;
        return { ...win, isOpen: nextState, zIndex: nextState ? Math.max(...prev.map(w => w.zIndex)) + 1 : win.zIndex };
      }
      return win;
    }));
  };

  const focusWindow = (id: AppId) => {
    setWindows(prev => {
      const maxZ = Math.max(...prev.map(w => w.zIndex));
      return prev.map(win => win.id === id ? { ...win, zIndex: maxZ + 1 } : win);
    });
  };

  const updateWindowState = (id: AppId, updates: Partial<AppWindow>) => {
    setWindows(prev => prev.map(win => win.id === id ? { ...win, ...updates } : win));
  };

  const renderAppContent = (id: AppId) => {
    switch (id) {
      case 'gemini': return <GeminiApp />;
      case 'files': return <FileExplorer />;
      case 'monitor': return <SystemMonitor />;
      case 'settings': return <div className="p-10 flex items-center justify-center text-white/50 h-full italic">System Configuration Utility - Under Maintenance</div>;
      case 'browser': return (
        <div className="flex flex-col h-full">
          <div className="bg-white/5 p-2 flex items-center gap-4">
            <input className="flex-1 bg-black/40 border border-white/10 rounded px-4 py-1 text-sm text-white/70" value="https://aurora.nexus/search?q=future" disabled />
          </div>
          <div className="flex-1 bg-white p-10 text-slate-800">
            <h1 className="text-3xl font-bold mb-4">Nexus Browser</h1>
            <p>Accessing decentralized data nodes...</p>
          </div>
        </div>
      );
      default: return null;
    }
  };

  return (
    <div className="h-screen w-screen overflow-hidden flex flex-col relative">

      {/* Desktop Background / Icons */}
      <main className="flex-1 p-6 relative z-10">
        <div className="grid grid-flow-col grid-rows-6 gap-6 w-fit h-fit">
          {(Object.keys(APPS_CONFIG) as AppId[]).map(id => (
            <div 
              key={id} 
              onClick={() => toggleWindow(id)}
              className="flex flex-col items-center gap-2 w-20 p-2 rounded-xl cursor-pointer hover:bg-white/10 group transition-all"
            >
              <div className={`${APPS_CONFIG[id].color} p-3 rounded-2xl text-white shadow-xl transform transition-transform group-active:scale-90`}>
                {APPS_CONFIG[id].icon}
              </div>
              <span className="text-[10px] font-bold text-white tracking-wide text-center drop-shadow-md">
                {APPS_CONFIG[id].name}
              </span>
            </div>
          ))}
        </div>

        {/* Dynamic Windows */}
        {windows.map(win => (
          <WindowFrame
            key={win.id}
            {...win}
            onClose={() => updateWindowState(win.id, { isOpen: false })}
            onMinimize={() => updateWindowState(win.id, { isOpen: false })}
            onMaximize={() => updateWindowState(win.id, { isMaximized: !win.isMaximized })}
            onFocus={() => focusWindow(win.id)}
          >
            {renderAppContent(win.id)}
          </WindowFrame>
        ))}
      </main>

      {/* Taskbar */}
      <footer className="h-14 glass-dark shrink-0 z-[1000] flex items-center px-4 justify-between border-t border-white/5">
        <div className="flex items-center gap-2">
          <button className="w-10 h-10 rounded-xl bg-indigo-600 hover:bg-indigo-500 shadow-[0_0_15px_rgba(79,70,229,0.4)] flex items-center justify-center text-white transition-all">
            <Power size={20} />
          </button>

          <div className="mx-4 h-6 w-px bg-white/10" />

          <div className="flex items-center gap-1">
            {(Object.keys(APPS_CONFIG) as AppId[]).map(id => (
              <button 
                key={id}
                onClick={() => {
                  if (windows.find(w => w.id === id)?.isOpen) {
                    focusWindow(id);
                  } else {
                    toggleWindow(id);
                  }
                }}
