import React, { useState, useRef, useEffect } from 'react';
import { X, Minus, Square, GripVertical } from 'lucide-react';
import { WindowPosition } from '../types';

interface WindowFrameProps {
  id: string;
  title: string;
  isOpen: boolean;
  isMaximized: boolean;
  zIndex: number;
  position: WindowPosition;
  onClose: () => void;
  onMinimize: () => void;
  onMaximize: () => void;
  onFocus: () => void;
  onMove: (pos: WindowPosition) => void;
  children: React.ReactNode;
}

const WindowFrame: React.FC<WindowFrameProps> = ({
  title,
  isOpen,
  isMaximized,
  zIndex,
  position,
  onClose,
  onMinimize,
  onMaximize,
  onFocus,
  onMove,
  children
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });
  const windowRef = useRef<HTMLDivElement>(null);

  if (!isOpen) return null;

  const handleMouseDown = (e: React.MouseEvent) => {
    onFocus();
    if (isMaximized) return;

    setIsDragging(true);
    setDragOffset({
      x: e.clientX - position.x,
      y: e.clientY - position.y
    });
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (isDragging) {
        onMove({
          x: e.clientX - dragOffset.x,
          y: e.clientY - dragOffset.y
        });
      }
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, dragOffset, onMove]);

  const windowClasses = isMaximized
    ? "fixed inset-0 z-[100]"
    : "fixed rounded-xl shadow-2xl transition-shadow duration-300 border border-white/10";

  const style: React.CSSProperties = isMaximized ? { zIndex } : {
    zIndex,
    left: `${position.x}px`,
    top: `${position.y}px`,
    width: '850px',
    height: '550px',
  };

  return (
    <div 
      ref={windowRef}
      className={`${windowClasses} glass-dark flex flex-col overflow-hidden ${isDragging ? 'shadow-indigo-500/20' : ''}`}
      style={style}
      onClick={onFocus}
    >
      {/* Barra de Título */}
      <div 
        onMouseDown={handleMouseDown}
        className={`h-11 flex items-center justify-between px-4 cursor-grab active:cursor-grabbing border-b border-white/5 bg-white/5 select-none`}
      >
        <div className="flex items-center gap-3">
          <GripVertical size={14} className="text-white/20" />
          <span className="text-xs font-semibold text-white/70 tracking-tight uppercase">{title}</span>
        </div>
        <div className="flex items-center gap-1.5">
          <button onClick={(e) => { e.stopPropagation(); onMinimize(); }} className="w-7 h-7 flex items-center justify-center hover:bg-white/10 rounded-lg transition-colors"><Minus size={14} /></button>
          <button onClick={(e) => { e.stopPropagation(); onMaximize(); }} className="w-7 h-7 flex items-center justify-center hover:bg-white/10 rounded-lg transition-colors"><Square size={12} /></button>
          <button onClick={(e) => { e.stopPropagation(); onClose(); }} className="w-7 h-7 flex items-center justify-center hover:bg-red-500/80 rounded-lg transition-colors"><X size={14} /></button>
        </div>
      </div>

      {/* Contenido */}
      <div className="flex-1 overflow-auto bg-slate-900/20 backdrop-blur-sm">
        {children}
      </div>
    </div>
  );
};

export default WindowFrame;

