    accentColor: '#6366f1',
    glassOpacity: 0.1,
    performanceMode: true,
    userName: 'Admin'
  });

  const [windows, setWindows] = useState<AppWindow[]>([
    { id: 'gemini', title: APPS_CONFIG.gemini.name, isOpen: false, isMaximized: false, isMinimized: false, zIndex: 10, position: { x: 100, y: 100 } },
    { id: 'files', title: APPS_CONFIG.files.name, isOpen: false, isMaximized: false, isMinimized: false, zIndex: 10, position: { x: 150, y: 150 } },
    { id: 'monitor', title: APPS_CONFIG.monitor.name, isOpen: false, isMaximized: false, isMinimized: false, zIndex: 10, position: { x: 200, y: 200 } },
    { id: 'settings', title: APPS_CONFIG.settings.name, isOpen: false, isMaximized: false, isMinimized: false, zIndex: 10, position: { x: 250, y: 250 } },
    { id: 'browser', title: APPS_CONFIG.browser.name, isOpen: false, isMaximized: false, isMinimized: false, zIndex: 10, position: { x: 300, y: 300 } },
  ]);

  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const focusWindow = useCallback((id: AppId) => {
    setWindows(prev => {
      const maxZ = Math.max(...prev.map(w => w.zIndex));
      return prev.map(win => win.id === id ? { ...win, zIndex: maxZ + 1, isMinimized: false } : win);
    });
  }, []);

  const toggleWindow = useCallback((id: AppId) => {
    setWindows(prev => prev.map(win => {
      if (win.id === id) {
        const nextState = !win.isOpen;
        if (nextState) focusWindow(id);
        return { ...win, isOpen: nextState, isMinimized: false };
      }
      return win;
    }));
  }, [focusWindow]);

  const moveWindow = useCallback((id: AppId, pos: WindowPosition) => {
    setWindows(prev => prev.map(win => win.id === id ? { ...win, position: pos } : win));
  }, []);

  const updateWindowState = (id: AppId, updates: Partial<AppWindow>) => {
    setWindows(prev => prev.map(win => win.id === id ? { ...win, ...updates } : win));
  };

  const renderAppContent = (id: AppId) => {
    switch (id) {
      case 'gemini': return <GeminiApp />;
      case 'files': return <FileExplorer />;
      case 'monitor': return <SystemMonitor />;
