      </div>

      {/* Desktop */}
      <main className="flex-1 p-8 relative z-10">
        <div className="grid grid-flow-col grid-rows-6 gap-8 w-fit">
          {(Object.keys(APPS_CONFIG) as AppId[]).map(id => (
            <div 
              key={id} 
              onDoubleClick={() => toggleWindow(id)}
              className="flex flex-col items-center gap-3 w-24 p-3 rounded-2xl cursor-pointer hover:bg-white/5 group transition-all"
            >
              <div className={`${APPS_CONFIG[id].color} w-16 h-16 rounded-[22px] flex items-center justify-center text-white shadow-2xl transform transition-all group-hover:scale-110 group-active:scale-95 group-hover:rotate-3`}>
                {APPS_CONFIG[id].icon}
              </div>
              <span className="text-[11px] font-bold text-white/80 tracking-tight text-center drop-shadow-lg uppercase">
                {APPS_CONFIG[id].name}
              </span>
            </div>
          ))}
        </div>

        {/* Capa de Ventanas */}
        {windows.map(win => (
          <WindowFrame
            key={win.id}
            {...win}
            onClose={() => updateWindowState(win.id, { isOpen: false })}
            onMinimize={() => updateWindowState(win.id, { isMinimized: true })}
            onMaximize={() => updateWindowState(win.id, { isMaximized: !win.isMaximized })}
            onFocus={() => focusWindow(win.id)}
            onMove={(pos) => moveWindow(win.id, pos)}
          >
            {renderAppContent(win.id)}
          </WindowFrame>
        ))}
      </main>

      {/* Taskbar Pro */}
      <footer className="h-16 glass-dark shrink-0 z-[1000] flex items-center px-6 justify-between border-t border-white/5">
        <div className="flex items-center gap-4">
          <button className="w-11 h-11 rounded-2xl bg-indigo-600 hover:bg-indigo-500 shadow-[0_0_25px_rgba(79,70,229,0.5)] flex items-center justify-center text-white transition-all transform hover:scale-105 active:scale-95">
            <Power size={22} strokeWidth={2.5} />
