const AriaApp: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: '# Conexión Establecida\n\nHola, soy **Aria**. El sistema Aurora OS está operativo bajo mi supervisión. ¿Qué hilos de datos deseas que exploremos hoy?', timestamp: new Date() }
  ]);
  const [input, setInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, isProcessing]);

  const handleSend = async () => {
    if (!input.trim() || isProcessing) return;
    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsProcessing(true);

    const response = await ariaCore.generateResponse(input, messages);
    setMessages(prev => [...prev, { role: 'assistant', content: response || 'Sin datos.', timestamp: new Date() }]);
    setIsProcessing(false);
  };

  return (
    <div className="flex flex-col h-full bg-slate-950/40">
      <div className="p-6 bg-indigo-900/10 border-b border-indigo-500/20 flex items-center justify-between">
        <div className="flex items-center gap-4">
