          </div>
        </div>
        <div className="flex gap-4">
            <div className="flex flex-col items-end">
                <span className="text-[9px] text-white/40 font-bold uppercase">Latencia Cuántica</span>
                <span className="text-xs font-mono text-emerald-400">1.2ms</span>
            </div>
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 p-8 overflow-y-auto space-y-8 scroll-smooth">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] flex gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
              <div className={`w-10 h-10 shrink-0 rounded-xl flex items-center justify-center shadow-lg ${msg.role === 'user' ? 'bg-indigo-600' : 'bg-slate-800 border border-white/10'}`}>
                {msg.role === 'user' ? <Zap size={20} /> : <Cpu size={20} />}
              </div>
              <div className={`p-5 rounded-2xl border ${
                msg.role === 'user' 
                  ? 'bg-indigo-600/90 text-white border-indigo-400 rounded-tr-none shadow-[0_10px_30px_rgba(99,102,241,0.2)]' 
                  : 'bg-slate-900/80 text-slate-200 border-white/5 rounded-tl-none shadow-xl'
              }`}>
                <div className="prose prose-invert prose-sm max-w-none prose-headings:text-indigo-300">
                   {msg.content}
                </div>
              </div>
            </div>
          </div>
        ))}
        {isProcessing && (
          <div className="flex justify-start">
            <div className="flex gap-4">
              <div className="w-10 h-10 rounded-xl bg-slate-800 flex items-center justify-center border border-white/10">
                <Loader2 className="w-5 h-5 animate-spin text-indigo-400" />
              </div>
              <div className="p-5 rounded-2xl bg-slate-900/40 border border-white/5 animate-pulse text-indigo-300/50 text-xs font-bold uppercase tracking-widest">
                Procesando hilos neurales...
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-8 bg-slate-950/60 border-t border-white/5">
        <div className="relative group max-w-4xl mx-auto">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Introduce comandos o consultas para Aria..."
            className="w-full bg-black/60 border border-white/10 rounded-2xl px-8 py-5 pr-20 focus:outline-none focus:ring-4 focus:ring-indigo-500/20 transition-all text-white placeholder-slate-600 font-medium"
          />
          <button 
            onClick={handleSend}
            disabled={isProcessing}
            className="absolute right-4 top-1/2 -translate-y-1/2 p-3 bg-indigo-600 hover:bg-indigo-500 disabled:bg-indigo-900 transition-all rounded-xl text-white shadow-lg active:scale-90"
          >
            <Send size={22} />
          </button>
        </div>
      </div>
    </div>
  );
};

