            <div className={`max-w-[90%] flex gap-6 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
              <div className={`w-12 h-12 shrink-0 rounded-2xl flex items-center justify-center shadow-2xl ${msg.role === 'user' ? 'bg-indigo-600 shadow-indigo-500/40' : 'bg-slate-900 border border-indigo-500/30 shadow-indigo-500/10'}`}>
