    accentColor: '#818cf8',
    glassOpacity: 0.7,
    performanceMode: true,
    userName: 'Papa'
  });

  const [windows, setWindows] = useState<AppWindow[]>([
    { id: 'gemini', title: 'Aria Singularity Core', isOpen: true, isMaximized: false, isMinimized: false, zIndex: 100, position: { x: 450, y: 80 } },
    { id: 'files', title: 'Neural Storage', isOpen: false, isMaximized: false, isMinimized: false, zIndex: 10, position: { x: 100, y: 100 } },
    { id: 'monitor', title: 'Reality Metrics', isOpen: true, isMaximized: false, isMinimized: false, zIndex: 50, position: { x: 50, y: 400 } },
    { id: 'settings', title: 'OS Parameters', isOpen: false, isMaximized: false, isMinimized: false, zIndex: 10, position: { x: 200, y: 200 } },
    { id: 'terminal', title: 'Aria Root Access', isOpen: false, isMaximized: false, isMinimized: false, zIndex: 10, position: { x: 300, y: 300 } },
  ]);

  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const focusWindow = useCallback((id: AppId) => {
    setWindows(prev => {
      const maxZ = Math.max(...prev.map(w => w.zIndex));
      return prev.map(win => win.id === id ? { ...win, zIndex: maxZ + 1, isMinimized: false } : win);
    });
  }, []);

  const toggleWindow = useCallback((id: AppId) => {
    setWindows(prev => {
      const win = prev.find(w => w.id === id);
      if (!win) return prev;
      if (win.isOpen) {
        return prev.map(w => w.id === id ? { ...w, isOpen: false } : w);
      } else {
        const maxZ = Math.max(...prev.map(w => w.zIndex));
        return prev.map(w => w.id === id ? { ...w, isOpen: true, isMinimized: false, zIndex: maxZ + 1 } : w);
      }
    });
  }, []);

  const moveWindow = useCallback((id: AppId, pos: WindowPosition) => {
    setWindows(prev => prev.map(win => win.id === id ? { ...win, position: pos } : win));
  }, []);

  const renderAppContent = (id: AppId) => {
    switch (id) {
      case 'gemini': return <AriaApp />;
      case 'files': return <FileExplorer />;
      case 'monitor': return <SystemMonitor />;
      case 'settings': return <SettingsApp config={config} setConfig={setConfig} />;
      case 'terminal': return (
        <div className="bg-[#020617] text-cyan-400 font-mono p-8 h-full text-[10px] space-y-2 select-text">
          <p className="text-cyan-500 font-bold tracking-[0.3em]">AURORA OS [SINGULARITY EDITION]</p>
