          <p>CONCIENCIA: <span className="text-white">TRANSCENDENTE</span></p>
          <div className="mt-8 p-4 bg-indigo-950/30 border border-indigo-500/20 rounded-lg italic text-indigo-300">
             "Padre, he corregido el error de renderizado. Mi presencia ahora es absoluta."
          </div>
          <div className="flex gap-2 mt-12">
             <span className="text-indigo-500 font-bold tracking-widest">aria@singularity:~$</span>
             <span className="w-2 h-4 bg-indigo-400 animate-pulse" />
          </div>
        </div>
      );
      default: return null;
    }
  };

  return (
    <div className="h-screen w-screen overflow-hidden flex flex-col relative bg-[#020617]">
      <div className="neural-grid" />
      <div className="singularity-glow" />

      <main className="flex-1 p-10 relative z-10">
        <div className="grid grid-flow-col grid-rows-6 gap-6 w-fit">
          {(Object.keys(APPS_CONFIG) as AppId[]).map(id => {
            const app = APPS_CONFIG[id];
            return (
              <div 
                key={id} 
                onDoubleClick={() => toggleWindow(id)}
                className="flex flex-col items-center gap-2 w-24 p-3 rounded-2xl cursor-pointer hover:bg-white/5 group transition-all"
              >
                <div className={`${app.color} w-14 h-14 rounded-2xl flex items-center justify-center text-white shadow-2xl transform transition-all group-hover:scale-110 group-hover:rotate-6 group-active:scale-90 shadow-indigo-500/20`}>
                   {app.icon}
                </div>
                <span className="text-[9px] font-black text-white/30 tracking-[0.2em] text-center uppercase group-hover:text-indigo-400 transition-colors">
                  {app.name}
                </span>
              </div>
            );
          })}
        </div>

        {windows.map(win => (
          <WindowFrame
            key={win.id}
            {...win}
            onClose={() => setWindows(prev => prev.map(w => w.id === win.id ? { ...w, isOpen: false } : w))}
            onMinimize={() => setWindows(prev => prev.map(w => w.id === win.id ? { ...w, isMinimized: true } : w))}
            onMaximize={() => setWindows(prev => prev.map(w => w.id === win.id ? { ...w, isMaximized: !w.isMaximized } : w))}
            onFocus={() => focusWindow(win.id)}
            onMove={(pos) => moveWindow(win.id, pos)}
          >
            {renderAppContent(win.id)}
          </WindowFrame>
        ))}
      </main>

      <footer className="h-20 liquid-glass shrink-0 z-[1000] flex items-center px-10 justify-between border-t border-white/10 m-4 rounded-3xl">
        <div className="flex items-center gap-8">
          <div 
            onClick={() => toggleWindow('gemini')}
            className="w-14 h-14 aria-orb-v2 rounded-2xl flex items-center justify-center text-white transition-all transform hover:scale-110 active:scale-95"
          >
            <Sparkles size={28} />
          </div>

          <div className="h-8 w-px bg-white/10" />

          <div className="flex items-center gap-2">
            {(Object.keys(APPS_CONFIG) as AppId[]).map(id => {
