import React, { useState, useRef, useEffect } from 'react';
import { X, Minus, Square, GripVertical } from 'lucide-react';
import { WindowPosition } from '../types';

interface WindowFrameProps {
  id: string;
  title: string;
  isOpen: boolean;
  isMaximized: boolean;
  zIndex: number;
  position: WindowPosition;
  onClose: () => void;
  onMinimize: () => void;
  onMaximize: () => void;
  onFocus: () => void;
  onMove: (pos: WindowPosition) => void;
  children: React.ReactNode;
}

const WindowFrame: React.FC<WindowFrameProps> = ({
  id,
  title,
  isOpen,
  isMaximized,
  zIndex,
  position,
  onClose,
  onMinimize,
  onMaximize,
  onFocus,
  onMove,
  children
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const dragStartPos = useRef({ x: 0, y: 0 });
  const windowRef = useRef<HTMLDivElement>(null);

  if (!isOpen) return null;

  const handlePointerDown = (e: React.PointerEvent) => {
    onFocus();
    if (isMaximized) return;

    // Solo permitir arrastre desde la barra de título o el grip
    const target = e.target as HTMLElement;
    if (!target.closest('.window-header')) return;

    setIsDragging(true);
    dragStartPos.current = {
      x: e.clientX - position.x,
      y: e.clientY - position.y
    };

    // Capturar el puntero para que el movimiento siga incluso fuera de la ventana
    (e.target as HTMLElement).setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging || isMaximized) return;

    onMove({
      x: e.clientX - dragStartPos.current.x,
      y: e.clientY - dragStartPos.current.y
    });
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (isDragging) {
      setIsDragging(false);
      (e.target as HTMLElement).releasePointerCapture(e.pointerId);
    }
  };

  const windowClasses = isMaximized
    ? "fixed inset-0 z-[100]"
    : "fixed rounded-2xl shadow-2xl border border-white/10 overflow-hidden window-hardware-accel";

  // Usar transform para máxima fluidez (GPU accelerated)
  const style: React.CSSProperties = isMaximized ? { zIndex } : {
    zIndex,
    transform: `translate3d(${position.x}px, ${position.y}px, 0)`,
    width: window.innerWidth < 768 ? '95vw' : '850px',
    height: window.innerWidth < 768 ? '70vh' : '550px',
    transition: isDragging ? 'none' : 'transform 0.2s cubic-bezier(0.2, 0, 0.2, 1), opacity 0.2s',
    opacity: isOpen ? 1 : 0,
  };

  return (
    <div 
      ref={windowRef}
      className={`${windowClasses} glass-dark flex flex-col ${isDragging ? 'shadow-indigo-500/30 scale-[1.01]' : 'scale-100'}`}
      style={style}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      onPointerCancel={handlePointerUp}
    >
      {/* Barra de Título (Header) */}
      <div 
        className="window-header h-12 flex items-center justify-between px-5 cursor-grab active:cursor-grabbing border-b border-white/5 bg-white/5 select-none touch-none"
      >
        <div className="flex items-center gap-3 pointer-events-none">
          <GripVertical size={16} className="text-indigo-400/40" />
          <span className="text-[10px] font-black text-white/60 tracking-widest uppercase">{title}</span>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onPointerDown={(e) => e.stopPropagation()} 
            onClick={onMinimize} 
            className="w-8 h-8 flex items-center justify-center hover:bg-white/10 rounded-xl transition-colors text-white/50"
          >
            <Minus size={16} />
          </button>
          <button 
            onPointerDown={(e) => e.stopPropagation()} 
            onClick={onMaximize} 
            className="w-8 h-8 flex items-center justify-center hover:bg-white/10 rounded-xl transition-colors text-white/50"
          >
            <Square size={14} />
          </button>
          <button 
            onPointerDown={(e) => e.stopPropagation()} 
            onClick={onClose} 
            className="w-8 h-8 flex items-center justify-center hover:bg-red-500/80 rounded-xl transition-colors text-white"
          >
            <X size={18} />
          </button>
        </div>
      </div>

      {/* Contenido con scroll optimizado para Android */}
      <div className="flex-1 overflow-auto custom-scrollbar bg-slate-900/10 backdrop-blur-sm pointer-events-auto">
        {children}
      </div>
    </div>
  );
};

export default WindowFrame;

