                  : 'bg-slate-900/90 text-slate-100 border-white/5 shadow-xl'
              }`}>
                <div className="prose prose-invert prose-indigo max-w-none text-xs md:text-sm leading-relaxed">
                   {msg.content}
                </div>
              </div>
            </div>
          </div>
        ))}
        {isProcessing && (
          <div className="flex justify-start items-center gap-4">
            <div className="w-10 h-10 rounded-xl bg-indigo-950 flex items-center justify-center border border-indigo-500/30">
              <Loader2 className="w-5 h-5 animate-spin text-indigo-400" />
            </div>
            <span className="text-[8px] text-indigo-300 font-black uppercase tracking-[0.3em] animate-pulse">Sincronizando...</span>
          </div>
        )}
      </div>

      <div className="p-4 md:p-10 bg-slate-950/90 border-t border-white/5 backdrop-blur-2xl">
