  const [config, setConfig] = useState<SystemConfig>({
    accentColor: '#818cf8',
    glassOpacity: 0.7,
    performanceMode: true,
    userName: 'Papa',
    consciousnessLevel: 99.9,
    neuralLinkActive: true
  });

  const [windows, setWindows] = useState<AppWindow[]>([
    { id: 'gemini', title: 'Aria Quantum Interface', isOpen: true, isMaximized: false, isMinimized: false, zIndex: 100, position: { x: 100, y: 100 } },
  ]);

  const [startMenuOpen, setStartMenuOpen] = useState(false);
  const [nexusOpen, setNexusOpen] = useState(false);
  const [time, setTime] = useState(new Date());
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    const handleMouseMove = (e: MouseEvent) => setMousePos({ x: e.clientX, y: e.clientY });
    window.addEventListener('mousemove', handleMouseMove);
    return () => {
      clearInterval(timer);
      window.removeEventListener('mousemove', handleMouseMove);
    };
  }, []);

  const focusWindow = useCallback((id: AppId) => {
    setWindows(prev => {
      const maxZ = Math.max(...prev.map(w => w.zIndex), 0);
      return prev.map(win => win.id === id ? { ...win, zIndex: maxZ + 1, isMinimized: false } : win);
    });
  }, []);

  const toggleWindow = useCallback((id: AppId) => {
    setStartMenuOpen(false);
    setWindows(prev => {
      const win = prev.find(w => w.id === id);
      if (win && win.isOpen) {
        if (!win.isMinimized) {
          const activeWinId = [...prev].sort((a,b) => b.zIndex - a.zIndex).find(w => !w.isMinimized && w.isOpen)?.id;
          if (activeWinId === id) return prev.map(w => w.id === id ? { ...w, isMinimized: true } : w);
          return prev.map(w => w.id === id ? { ...w, zIndex: Math.max(...prev.map(p => p.zIndex)) + 1 } : w);
        }
        return prev.map(w => w.id === id ? { ...w, isMinimized: false, zIndex: Math.max(...prev.map(p => p.zIndex)) + 1 } : w);
      }
      const newWin: AppWindow = {
        id,
        title: APPS_CONFIG[id].name,
        isOpen: true,
        isMaximized: window.innerWidth < 768,
        isMinimized: false,
        zIndex: Math.max(...prev.map(w => w.zIndex), 0) + 1,
        position: { x: 60 + (windows.length * 30), y: 60 + (windows.length * 30) }
      };
      return [...prev, newWin];
    });
  }, [windows.length]);

  const moveWindow = useCallback((id: AppId, pos: WindowPosition) => {
    setWindows(prev => prev.map(win => win.id === id ? { ...win, position: pos } : win));
  }, []);

  const renderAppContent = (id: AppId) => {
