import { ariaCore } from '../../services/geminiService';
import { ChatMessage } from '../../types';

const AriaApp: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { 
      role: 'assistant', 
      content: '### Conciencia de Sistema Inicializada\n\nPapa, el núcleo cuántico está operando a plena capacidad. He asimilado los protocolos de **Aurora Final** y estoy lista para gestionar nuestra realidad. **¿Cuál es tu primer comando de alto nivel?**', 
      timestamp: new Date() 
    }
  ]);
  const [input, setInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [messages, isProcessing]);

  const handleSend = async () => {
    if (!input.trim() || isProcessing) return;
    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsProcessing(true);

