        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[92%] md:max-w-[80%] flex gap-4 md:gap-8 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
              <div className={`w-10 h-10 md:w-14 md:h-14 shrink-0 rounded-2xl flex items-center justify-center shadow-2xl transform transition-transform hover:rotate-12 ${msg.role === 'user' ? 'bg-indigo-600' : 'bg-slate-900 border border-indigo-500/30'}`}>
