              </div>
              <div className={`p-6 md:p-8 rounded-[2rem] border shadow-2xl relative ${
                msg.role === 'user' 
                  ? 'bg-indigo-600/10 text-white border-indigo-500/40 backdrop-blur-md' 
                  : 'bg-slate-900/80 text-slate-100 border-white/5 backdrop-blur-xl'
