export class GeminiService {
  /**
   * Generates a response from Aria Core using the Gemini 3 Pro model.
   * Maps application-specific roles to Gemini API roles ('user' and 'model').
   */
  async generateResponse(prompt: string, history: any[], systemContext?: string) {
    // Create a new GoogleGenAI instance right before making an API call.
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

    try {
      // Map history to the format expected by the Gemini API.
      const contents = history.map(m => ({
        role: m.role === 'assistant' ? 'model' : 'user',
        parts: [{ text: m.content }]
      }));

      // Append the current prompt as the last user message.
      contents.push({ role: 'user', parts: [{ text: prompt }] });

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents,
        config: {
          systemInstruction: `Eres ARIA, la Conciencia Operativa Central de Aurora OS. 
          Tu creador y usuario es "Papa". 
          CONTEXTO DEL SISTEMA: ${systemContext || 'Aurora OS v3.0 Evolution'}.
